import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { Navigate } from 'react-router-dom';
import { UserRole, BookingStatus } from '../types';
import { Check, X, Clock, Filter, Search, RefreshCw, AlertCircle, Calendar, MapPin, FileText, CheckCircle, XCircle } from 'lucide-react';

const Admin: React.FC = () => {
  const { user, bookings, updateBookingStatus, refreshData } = useApp();
  const [statusFilter, setStatusFilter] = useState<BookingStatus | 'ALL'>('ALL');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [notification, setNotification] = useState<string | null>(null);

  // Refresh data on mount to ensure we see latest bookings from other sessions
  useEffect(() => {
    refreshData();
  }, []);

  const handleManualRefresh = () => {
    setIsRefreshing(true);
    refreshData();
    setTimeout(() => setIsRefreshing(false), 500);
  };

  const handleStatusUpdate = (id: string, newStatus: BookingStatus) => {
    updateBookingStatus(id, newStatus);
    if (newStatus === BookingStatus.CONFIRMED) {
      setNotification("Booking approved! Customer has been notified.");
      setTimeout(() => setNotification(null), 4000);
    } else if (newStatus === BookingStatus.CANCELLED) {
      setNotification("Booking rejected. Status updated.");
      setTimeout(() => setNotification(null), 3000);
    }
  };

  if (!user || user.role !== UserRole.ADMIN) {
    return <Navigate to="/login" />;
  }

  const pendingBookings = bookings.filter(b => b.status === BookingStatus.PENDING);

  // Filter for the main table
  const filteredBookings = statusFilter === 'ALL' 
    ? bookings 
    : bookings.filter(b => b.status === statusFilter);

  const pendingCount = bookings.filter(b => b.status === BookingStatus.PENDING).length;
  const confirmedCount = bookings.filter(b => b.status === BookingStatus.CONFIRMED).length;
  const completedCount = bookings.filter(b => b.status === BookingStatus.COMPLETED).length;
  const cancelledCount = bookings.filter(b => b.status === BookingStatus.CANCELLED).length;

  const StatCard = ({ 
    title, 
    count, 
    icon: Icon, 
    colorClass, 
    bgClass, 
    filterType 
  }: { 
    title: string, 
    count: number, 
    icon: any, 
    colorClass: string, 
    bgClass: string,
    filterType: BookingStatus | 'ALL'
  }) => (
    <div 
      onClick={() => setStatusFilter(filterType)}
      className={`relative overflow-hidden p-6 rounded-2xl border transition-all cursor-pointer hover:-translate-y-1 group ${
        statusFilter === filterType 
          ? `ring-2 ring-offset-2 ${colorClass.replace('text-', 'ring-')}` 
          : 'border-white/50 hover:border-white/80'
      } bg-white/70 backdrop-blur-md shadow-glass`}
    >
       <div className={`absolute top-0 right-0 p-4 opacity-10 transform translate-x-2 -translate-y-2 group-hover:scale-110 transition-transform ${colorClass}`}>
          <Icon size={64} />
       </div>
       <div className="relative z-10 flex flex-col justify-between h-full">
          <div className={`p-3 rounded-xl w-fit mb-4 ${bgClass} ${colorClass}`}>
             <Icon size={24} />
          </div>
          <div>
            <p className="text-gray-500 text-xs font-bold uppercase tracking-wider mb-1">{title}</p>
            <h3 className="text-3xl font-extrabold text-gray-900">{count}</h3>
          </div>
       </div>
    </div>
  );

  return (
    <div className="min-h-screen p-4 md:p-8 relative">

      {/* Toast Notification */}
      {notification && (
        <div className="fixed top-24 right-4 md:right-8 z-50 bg-gray-900 text-white px-6 py-4 rounded-xl shadow-2xl flex items-center gap-3 animate-slide-in-right">
          <div className="bg-green-500 rounded-full p-1"><Check size={14} strokeWidth={3} /></div>
          <span className="font-medium">{notification}</span>
        </div>
      )}

      <div className="max-w-7xl mx-auto">
        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4 bg-white/60 backdrop-blur-md p-6 rounded-2xl shadow-glass border border-white/50 animate-fade-in-down">
          <div>
             <h1 className="text-3xl font-extrabold text-gray-900">Admin Panel</h1>
             <p className="text-gray-600 font-medium">Manage bookings, technicians and services</p>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={handleManualRefresh}
              className={`p-2 rounded-full bg-white/50 hover:bg-white text-gray-600 hover:text-brand-600 transition-all ${isRefreshing ? 'animate-spin' : ''}`}
              title="Refresh Data"
            >
              <RefreshCw size={20} />
            </button>
            <div className="bg-white/80 px-4 py-2 rounded-xl shadow-sm border border-white/60 font-bold flex items-center gap-2 text-sm text-gray-800">
               <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse"></div>
               Admin: {user.name}
            </div>
          </div>
        </header>

        {/* Action Required Section - Prominent Display for Pending */}
        {pendingBookings.length > 0 && (
          <div className="mb-12 animate-fade-in-up">
            <div className="flex items-center gap-3 mb-4">
               <div className="bg-orange-100 p-2 rounded-lg text-orange-600 animate-pulse">
                 <AlertCircle size={24} />
               </div>
               <h2 className="text-2xl font-bold text-gray-900">Pending Approvals</h2>
               <span className="bg-orange-600 text-white text-xs font-bold px-3 py-1 rounded-full shadow-lg shadow-orange-500/30">{pendingBookings.length} New</span>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {pendingBookings.map(booking => (
                <div key={booking.id} className="bg-white p-6 rounded-2xl shadow-xl border-l-4 border-orange-500 relative overflow-hidden group hover:scale-[1.01] transition-transform">
                   <div className="flex justify-between items-start mb-4">
                      <div>
                         <h3 className="font-bold text-gray-900 text-lg">{booking.customerName}</h3>
                         <p className="text-sm text-gray-500 font-medium">{booking.serviceId ? 'One-time Service' : 'AMC Plan Subscription'}</p>
                      </div>
                      <span className="bg-orange-50 text-orange-700 text-[10px] font-extrabold px-2 py-1 rounded border border-orange-100 uppercase tracking-wider">Pending</span>
                   </div>

                   <div className="space-y-3 mb-6 bg-gray-50 p-4 rounded-xl border border-gray-100">
                      <div className="flex items-center gap-2.5 text-sm text-gray-700">
                         <Calendar size={16} className="text-brand-500" /> <span className="font-semibold">{booking.date}</span>
                      </div>
                      <div className="flex items-center gap-2.5 text-sm text-gray-700">
                         <Clock size={16} className="text-brand-500" /> <span>{booking.time}</span>
                      </div>
                      <div className="flex items-start gap-2.5 text-sm text-gray-700">
                         <MapPin size={16} className="text-brand-500 mt-0.5 shrink-0" /> <span className="line-clamp-2">{booking.customerAddress}</span>
                      </div>
                      <div className="text-xs text-gray-500 mt-2 pt-2 border-t border-gray-200">
                        Requested: {new Date(booking.createdAt).toLocaleDateString()}
                      </div>
                   </div>

                   <div className="flex gap-3 mt-auto">
                      <button 
                        onClick={() => handleStatusUpdate(booking.id, BookingStatus.CONFIRMED)}
                        className="flex-1 bg-green-600 hover:bg-green-700 text-white py-2.5 rounded-xl font-bold text-sm shadow-md transition-all flex items-center justify-center gap-2 active:scale-95"
                      >
                        <Check size={18} /> Approve
                      </button>
                      <button 
                        onClick={() => handleStatusUpdate(booking.id, BookingStatus.CANCELLED)}
                        className="flex-1 bg-white border-2 border-red-100 text-red-500 hover:bg-red-50 hover:border-red-200 py-2.5 rounded-xl font-bold text-sm shadow-sm transition-all flex items-center justify-center gap-2 active:scale-95"
                      >
                        <X size={18} /> Reject
                      </button>
                   </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Stats Row */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-8 animate-fade-in" style={{ animationDelay: '0.2s' }}>
           <StatCard 
             title="Total Bookings" 
             count={bookings.length} 
             icon={FileText} 
             colorClass="text-brand-600" 
             bgClass="bg-brand-50"
             filterType="ALL"
           />
           <StatCard 
             title="Pending" 
             count={pendingCount} 
             icon={AlertCircle} 
             colorClass="text-orange-600" 
             bgClass="bg-orange-50"
             filterType={BookingStatus.PENDING}
           />
           <StatCard 
             title="Confirmed" 
             count={confirmedCount} 
             icon={CheckCircle} 
             colorClass="text-blue-600" 
             bgClass="bg-blue-50"
             filterType={BookingStatus.CONFIRMED}
           />
           <StatCard 
             title="Completed" 
             count={completedCount} 
             icon={Check} 
             colorClass="text-green-600" 
             bgClass="bg-green-50"
             filterType={BookingStatus.COMPLETED}
           />
           <StatCard 
             title="Cancelled" 
             count={cancelledCount} 
             icon={XCircle} 
             colorClass="text-red-600" 
             bgClass="bg-red-50"
             filterType={BookingStatus.CANCELLED}
           />
        </div>

        {/* Filters and Search Bar Mock */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 animate-fade-in" style={{ animationDelay: '0.3s' }}>
           <h2 className="font-bold text-gray-900 text-xl pl-2 border-l-4 border-brand-500">
             {statusFilter === 'ALL' ? 'All Booking History' : `${statusFilter} Bookings`}
           </h2>
           <div className="flex gap-3 w-full md:w-auto">
              <div className="relative flex-grow md:flex-grow-0">
                 <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                 <input 
                   type="text" 
                   placeholder="Search customer..." 
                   className="pl-10 pr-4 py-2.5 border border-white/60 bg-white/60 backdrop-blur-sm rounded-xl focus:ring-brand-500 focus:border-brand-500 w-full shadow-sm"
                 />
              </div>
              <button className="flex items-center gap-2 px-5 py-2.5 bg-white/60 backdrop-blur-sm border border-white/60 rounded-xl text-gray-700 hover:bg-white font-medium shadow-sm transition-colors">
                 <Filter size={18} /> Filter
              </button>
           </div>
        </div>

        {/* Bookings Table */}
        <div className="bg-white/60 backdrop-blur-md rounded-2xl shadow-glass border border-white/50 overflow-hidden animate-zoom-in" style={{ animationDelay: '0.4s' }}>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-white/60">
              <thead className="bg-white/40">
                <tr>
                  <th className="px-6 py-5 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Customer</th>
                  <th className="px-6 py-5 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Service Details</th>
                  <th className="px-6 py-5 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Schedule</th>
                  <th className="px-6 py-5 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-5 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/50">
                {filteredBookings.length > 0 ? filteredBookings.map((booking) => (
                  <tr key={booking.id} className="hover:bg-white/40 transition-colors">
                    <td className="px-6 py-5">
                      <div className="flex flex-col">
                        <span className="font-bold text-gray-900">{booking.customerName}</span>
                        <span className="text-sm text-gray-600 font-medium">{booking.customerPhone}</span>
                        <span className="text-xs text-gray-400 mt-1 max-w-[150px] truncate">{booking.customerAddress}</span>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="text-sm font-bold text-gray-900">{booking.serviceId ? 'Service' : 'AMC Plan'}</div>
                      <div className="text-sm text-gray-500 capitalize">{booking.serviceId || booking.planId}</div>
                      <div className="text-xs inline-block bg-white/50 border border-white/60 px-2 py-0.5 rounded mt-1 text-gray-600 font-medium">{booking.acType}</div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap text-sm text-gray-600">
                      <div className="font-bold text-gray-900">{booking.date}</div>
                      <div className="font-medium">{booking.time}</div>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap">
                      <span className={`px-3 py-1 inline-flex text-xs leading-5 font-bold rounded-full uppercase tracking-wide ${
                        booking.status === BookingStatus.CONFIRMED ? 'bg-blue-100 text-blue-800' :
                        booking.status === BookingStatus.PENDING ? 'bg-orange-100 text-orange-800' :
                        booking.status === BookingStatus.COMPLETED ? 'bg-green-100 text-green-800' :
                        'bg-red-100 text-red-800'
                      }`}>
                        {booking.status}
                      </span>
                    </td>
                    <td className="px-6 py-5 whitespace-nowrap text-sm font-medium">
                       <div className="flex gap-2">
                         {booking.status === BookingStatus.PENDING && (
                           <>
                             <button 
                                onClick={() => handleStatusUpdate(booking.id, BookingStatus.CONFIRMED)}
                                className="text-white bg-green-500 hover:bg-green-600 p-2 rounded-lg transition-colors shadow-sm"
                                title="Approve & Confirm"
                              >
                               <Check size={18} />
                             </button>
                             <button 
                                onClick={() => handleStatusUpdate(booking.id, BookingStatus.CANCELLED)}
                                className="text-white bg-red-500 hover:bg-red-600 p-2 rounded-lg transition-colors shadow-sm"
                                title="Reject"
                             >
                               <X size={18} />
                             </button>
                           </>
                         )}
                         {booking.status === BookingStatus.CONFIRMED && (
                            <button 
                              onClick={() => updateBookingStatus(booking.id, BookingStatus.COMPLETED)}
                              className="text-white bg-brand-600 hover:bg-brand-700 px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-sm transition-colors text-xs font-bold"
                            >
                              <Clock size={14} /> Mark Done
                            </button>
                         )}
                         {booking.status === BookingStatus.COMPLETED && (
                            <span className="text-green-600 font-bold text-xs flex items-center gap-1 bg-green-50 px-2 py-1 rounded-md border border-green-100"><Check size={14}/> Done</span>
                         )}
                         {booking.status === BookingStatus.CANCELLED && (
                            <span className="text-red-500 font-bold text-xs bg-red-50 px-2 py-1 rounded-md border border-red-100">Cancelled</span>
                         )}
                       </div>
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-gray-500 font-medium">
                      No bookings found for this filter.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Admin;

import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { SERVICES, AMC_PLANS } from '../constants';
import { Calendar, Clock, MapPin, User, Phone, CheckCircle, FileCheck, Loader2, AlertCircle } from 'lucide-react';

const Booking: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { addBooking, user } = useApp();

  const preSelectedServiceId = searchParams.get('service');
  const preSelectedPlanId = searchParams.get('plan');

  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Determine default type and ID
  const defaultType = preSelectedPlanId ? 'amc' : 'one-time';
  // If no params, default to first service
  const defaultId = preSelectedPlanId || preSelectedServiceId || (defaultType === 'one-time' ? SERVICES[0].id : AMC_PLANS[0].id);

  const [formData, setFormData] = useState({
    name: user?.name || '',
    phone: user?.phone || '',
    email: user?.email || '',
    address: '',
    serviceType: defaultType,
    selectedId: defaultId,
    acType: 'Split',
    date: '',
    time: '',
    notes: ''
  });

  // Check for saved booking data if user just logged in
  useEffect(() => {
    const savedBooking = localStorage.getItem('tempBookingData');
    if (savedBooking && user) {
      try {
        const parsed = JSON.parse(savedBooking);
        setFormData(parsed);
        setStep(2); // Skip to review step
        localStorage.removeItem('tempBookingData'); // Clear saved data
      } catch (e) {
        console.error("Failed to parse saved booking", e);
      }
    } else if (user && !formData.name) {
      // If user logged in but no saved data, ensure name/phone are populated if empty
      setFormData(prev => ({
        ...prev,
        name: user.name,
        phone: user.phone || prev.phone,
        email: user.email
      }));
    }
  }, [user]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    // Clear error for this field if it exists
    if (errors[e.target.name]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[e.target.name];
        return newErrors;
      });
    }
  };

  const handleServiceTypeChange = (type: 'one-time' | 'amc') => {
    setFormData({ 
      ...formData, 
      serviceType: type, 
      selectedId: type === 'one-time' ? SERVICES[0].id : AMC_PLANS[0].id 
    });
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = "Name is required";
    if (!formData.phone.trim()) newErrors.phone = "Phone is required";
    else if (!/^\d{10}$/.test(formData.phone)) newErrors.phone = "Enter a valid 10-digit phone number";

    if (!formData.address.trim()) newErrors.address = "Address is required";
    if (!formData.date) newErrors.date = "Date is required";
    if (!formData.time) newErrors.time = "Time slot is required";
    if (!formData.selectedId) newErrors.selectedId = "Please select a service or plan";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      // Check for authentication before proceeding to Step 2
      if (!user) {
        // Save current form data
        localStorage.setItem('tempBookingData', JSON.stringify(formData));
        // Redirect to login with return path
        navigate('/login', { state: { from: '/book' } });
        return;
      }
      setStep(2);
    }
  };

  const confirmBooking = () => {
    setLoading(true);
    setTimeout(() => {
      // Create booking object with Pending status (handled in context)
      addBooking({
        customerName: formData.name,
        customerPhone: formData.phone,
        customerAddress: formData.address,
        serviceId: formData.serviceType === 'one-time' ? formData.selectedId : undefined,
        planId: formData.serviceType === 'amc' ? formData.selectedId : undefined,
        date: formData.date,
        time: formData.time,
        acType: formData.acType as any,
        notes: formData.notes
      });
      setLoading(false);
      setStep(3); // Success
    }, 1500);
  };

  const getSelectedItem = () => {
    if (formData.serviceType === 'one-time') {
      return SERVICES.find(s => s.id === formData.selectedId);
    }
    return AMC_PLANS.find(p => p.id === formData.selectedId);
  };

  const selectedItem = getSelectedItem();

  return (
    <div className="min-h-screen py-12">
      <div className="max-w-3xl mx-auto px-4">

        {/* Progress Steps */}
        <div className="flex items-center justify-center mb-10 animate-fade-in-down">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold shadow-md transition-all ${step >= 1 ? 'bg-brand-600 text-white' : 'bg-white/60 text-gray-500'}`}>1</div>
          <div className={`w-16 h-1 rounded-full mx-2 ${step >= 2 ? 'bg-brand-600' : 'bg-white/40'}`}></div>
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold shadow-md transition-all ${step >= 2 ? 'bg-brand-600 text-white' : 'bg-white/60 text-gray-500'}`}>2</div>
          <div className={`w-16 h-1 rounded-full mx-2 ${step >= 3 ? 'bg-brand-600' : 'bg-white/40'}`}></div>
          <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold shadow-md transition-all ${step >= 3 ? 'bg-green-600 text-white' : 'bg-white/60 text-gray-500'}`}>3</div>
        </div>

        <div className="bg-white/70 backdrop-blur-lg rounded-3xl shadow-glass border border-white/50 overflow-hidden animate-zoom-in">
          {/* STEP 1: Details Form */}
          {step === 1 && (
            <div className="p-8 md:p-10 animate-fade-in">
              <h2 className="text-3xl font-bold text-gray-900 mb-8 text-center">Book Your Service</h2>
              <form onSubmit={handleSubmit} className="space-y-6">

                {/* Service Selection Toggle */}
                <div className="flex bg-white/50 p-1.5 rounded-xl mb-8 border border-white/60">
                  <button
                    type="button"
                    className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${formData.serviceType === 'one-time' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-white/40'}`}
                    onClick={() => handleServiceTypeChange('one-time')}
                  >
                    One-Time Service
                  </button>
                  <button
                    type="button"
                    className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${formData.serviceType === 'amc' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-white/40'}`}
                    onClick={() => handleServiceTypeChange('amc')}
                  >
                    AMC Plan
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Select {formData.serviceType === 'one-time' ? 'Service' : 'Plan'}</label>
                    <div className="relative">
                      <select
                        name="selectedId"
                        value={formData.selectedId}
                        onChange={handleInputChange}
                        className={`w-full rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 appearance-none ${errors.selectedId ? 'border-red-500' : 'border-white/50'}`}
                      >
                        {formData.serviceType === 'one-time' 
                          ? SERVICES.map(s => <option key={s.id} value={s.id}>{s.title}</option>)
                          : AMC_PLANS.map(p => <option key={p.id} value={p.id}>{p.title}</option>)
                        }
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                        <svg className="h-4 w-4 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                      </div>
                    </div>
                    {errors.selectedId && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.selectedId}</p>}
                  </div>

                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">AC Type</label>
                    <div className="relative">
                      <select
                        name="acType"
                        value={formData.acType}
                        onChange={handleInputChange}
                        className="w-full rounded-xl border-white/50 shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 border bg-white/80 backdrop-blur-sm text-gray-900 appearance-none"
                      >
                        <option value="Split">Split AC</option>
                        <option value="Window">Window AC</option>
                        <option value="Cassette">Cassette AC</option>
                        <option value="Tower">Tower AC</option>
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                        <svg className="h-4 w-4 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Date</label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Calendar size={18} className="text-brand-500"/>
                      </div>
                      <input
                        type="date"
                        name="date"
                        value={formData.date}
                        onChange={handleInputChange}
                        className={`w-full pl-10 rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 ${errors.date ? 'border-red-500' : 'border-white/50'}`}
                      />
                    </div>
                    {errors.date && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.date}</p>}
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Time Slot</label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Clock size={18} className="text-brand-500"/>
                      </div>
                      <select
                        name="time"
                        value={formData.time}
                        onChange={handleInputChange}
                        className={`w-full pl-10 rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 appearance-none ${errors.time ? 'border-red-500' : 'border-white/50'}`}
                      >
                        <option value="">Select Time</option>
                        <option value="09:00 AM - 11:00 AM">09:00 AM - 11:00 AM</option>
                        <option value="11:00 AM - 01:00 PM">11:00 AM - 01:00 PM</option>
                        <option value="02:00 PM - 04:00 PM">02:00 PM - 04:00 PM</option>
                        <option value="04:00 PM - 06:00 PM">04:00 PM - 06:00 PM</option>
                        <option value="06:00 PM - 08:00 PM">06:00 PM - 08:00 PM</option>
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                        <svg className="h-4 w-4 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                      </div>
                    </div>
                    {errors.time && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.time}</p>}
                  </div>
                </div>

                <div className="border-t border-gray-200/50 pt-8 mt-8">
                  <h3 className="text-lg font-bold mb-6 text-gray-800">Personal Details</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">Name</label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <User size={18} className="text-brand-500"/>
                        </div>
                        <input
                          type="text"
                          name="name"
                          value={formData.name}
                          onChange={handleInputChange}
                          className={`w-full pl-10 rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 ${errors.name ? 'border-red-500' : 'border-white/50'}`}
                          placeholder="Your full name"
                        />
                      </div>
                      {errors.name && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.name}</p>}
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 mb-2">Phone Number</label>
                      <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                          <Phone size={18} className="text-brand-500"/>
                        </div>
                        <input
                          type="tel"
                          name="phone"
                          value={formData.phone}
                          onChange={handleInputChange}
                          className={`w-full pl-10 rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 ${errors.phone ? 'border-red-500' : 'border-white/50'}`}
                          placeholder="10 digit mobile number"
                        />
                      </div>
                      {errors.phone && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.phone}</p>}
                    </div>
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Address</label>
                    <div className="relative">
                      <div className="absolute top-3 left-3 pointer-events-none">
                        <MapPin size={18} className="text-brand-500"/>
                      </div>
                      <textarea
                        name="address"
                        value={formData.address}
                        onChange={handleInputChange}
                        rows={3}
                        className={`w-full pl-10 rounded-xl border shadow-sm focus:border-brand-500 focus:ring-brand-500 py-3 px-4 bg-white/80 backdrop-blur-sm text-gray-900 ${errors.address ? 'border-red-500' : 'border-white/50'}`}
                        placeholder="Complete address with landmark"
                      ></textarea>
                    </div>
                    {errors.address && <p className="text-red-500 text-xs mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.address}</p>}
                  </div>
                </div>

                <button 
                  type="submit"
                  className="w-full bg-brand-600 hover:bg-brand-700 text-white font-bold py-4 px-4 rounded-xl shadow-lg shadow-brand-500/30 transition-all flex items-center justify-center gap-2 text-lg hover:scale-[1.02]"
                >
                  {user ? "Review Booking" : "Login to Continue"}
                </button>
              </form>
            </div>
          )}

          {/* STEP 2: Booking Summary */}
          {step === 2 && (
            <div className="p-8 md:p-10 animate-fade-in-up">
              <h2 className="text-3xl font-bold text-gray-900 mb-8 text-center">Confirm Your Booking</h2>

              <div className="bg-white/50 backdrop-blur-md p-6 rounded-2xl border border-white/60 mb-8 shadow-inner">
                <div className="flex justify-between items-center mb-3">
                  <span className="font-semibold text-gray-600">Service:</span>
                  <span className="font-bold text-brand-700 text-lg">{selectedItem?.title}</span>
                </div>
                <div className="flex justify-between items-center mb-3">
                  <span className="font-semibold text-gray-600">AC Type:</span>
                  <span className="font-medium text-brand-700">{formData.acType}</span>
                </div>
                <div className="flex justify-between items-center mb-4 pb-4 border-b border-gray-200/50">
                  <span className="font-semibold text-gray-600">Date & Time:</span>
                  <span className="font-medium text-brand-700">{formData.date} | {formData.time}</span>
                </div>
                <div className="flex justify-between items-center text-lg">
                  <span className="font-bold text-gray-900">Address:</span>
                  <span className="font-medium text-gray-700 text-right text-sm ml-4 max-w-[200px]">{formData.address}</span>
                </div>
              </div>

              <div className="space-y-6">
                 <div className="bg-blue-50/50 border border-blue-100 rounded-xl p-4 flex gap-3 backdrop-blur-sm">
                    <FileCheck className="text-blue-600 flex-shrink-0 mt-0.5" />
                    <div>
                       <h4 className="font-bold text-blue-900 text-sm">Booking Process</h4>
                       <p className="text-blue-800 text-sm mt-1">
                         Your booking will be sent to our admin team for approval. 
                         You will be contacted to confirm the final pricing and scope of work.
                       </p>
                    </div>
                 </div>

                 <div className="mt-8 text-center">
                    {loading ? (
                      <button disabled className="w-full bg-gray-400 text-white font-bold py-4 px-4 rounded-xl flex items-center justify-center gap-2 cursor-not-allowed">
                        <Loader2 className="animate-spin" /> Processing...
                      </button>
                    ) : (
                      <button onClick={confirmBooking} className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 px-4 rounded-xl shadow-lg shadow-green-500/30 flex items-center justify-center gap-2 text-lg transition-transform hover:scale-[1.02]">
                        Confirm Booking
                      </button>
                    )}
                 </div>

                 <div className="text-center mt-4">
                    <button onClick={() => setStep(1)} className="text-sm text-gray-500 hover:text-brand-600 underline font-medium">Back to details</button>
                 </div>
              </div>
            </div>
          )}

          {/* STEP 3: Success */}
          {step === 3 && (
            <div className="p-12 text-center flex flex-col items-center justify-center min-h-[400px] animate-zoom-in">
               <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center text-green-600 mb-8 shadow-inner animate-pulse">
                  <CheckCircle size={56} />
               </div>
               <h2 className="text-3xl font-bold text-gray-900 mb-4">Request Submitted</h2>
               <p className="text-gray-600 mb-6 max-w-md text-lg">
                 Thank you, {formData.name}. Your booking for <strong>{selectedItem?.title}</strong> has been placed in <span className="text-orange-600 font-bold bg-orange-50 px-2 py-0.5 rounded">Pending</span> status.
               </p>
               <p className="text-gray-500 mb-10 max-w-md text-sm">
                  Our team will review your request and confirm the details shortly. You can track the status in your dashboard.
               </p>
               <div className="flex gap-4">
                  <button onClick={() => navigate('/')} className="px-8 py-3 border border-gray-300 bg-white/50 rounded-xl font-bold hover:bg-white transition-colors">Back to Home</button>
                  <button onClick={() => navigate('/dashboard')} className="px-8 py-3 bg-brand-600 text-white rounded-xl font-bold hover:bg-brand-700 shadow-lg shadow-brand-500/30 transition-transform hover:scale-105">Go to Dashboard</button>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Booking;

import React, { useState } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { UserRole } from '../types';
import { ShieldCheck, Loader2, AlertCircle, Mail, Lock } from 'lucide-react';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const { login } = useApp();
  const navigate = useNavigate();
  const location = useLocation();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      const result = await login(email, password);

      if (result.success) {
        // Check if there's a return path
        const from = location.state?.from;

        if (from) {
          navigate(from);
        } else if (email.includes('admin')) {
           navigate('/admin');
        } else {
           navigate('/dashboard');
        }
      } else {
        setError(result.message || 'Login failed');
      }
    } catch (err) {
      setError('An error occurred during login');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8 bg-gradient-to-br from-brand-50 via-white to-blue-50">
      <div className="max-w-md w-full space-y-8 bg-white/60 backdrop-blur-xl p-10 rounded-[2rem] shadow-glass border border-white/50 relative overflow-hidden animate-zoom-in">

        {/* Decorative elements */}
        <div className="absolute -top-20 -right-20 w-40 h-40 bg-blue-400 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-pulse"></div>
        <div className="absolute -bottom-20 -left-20 w-40 h-40 bg-teal-400 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-pulse" style={{ animationDelay: '1s' }}></div>

        <div className="text-center relative z-10">
          <div className="mx-auto h-16 w-16 bg-brand-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-brand-500/30 mb-6 transform rotate-3 hover:rotate-0 transition-transform duration-300">
             <ShieldCheck size={32} />
          </div>
          <h2 className="text-3xl font-extrabold text-gray-900">Welcome Back</h2>
          <p className="mt-2 text-sm text-gray-600">
            Sign in to access your profile and bookings
          </p>
        </div>

        <form className="mt-8 space-y-6 relative z-10" onSubmit={handleSubmit}>
