  try {
    // Check if import.meta.env exists
    if (typeof import.meta !== 'undefined' && (import.meta as any).env) {
      return (import.meta as any).env[key];
    }
  } catch (e) {
    console.warn(`Failed to access env var ${key}`, e);
  }
  return undefined;
};

